lines = data.strip().split('\n')
headers = lines[0].split('\t')
values = lines[1].split('\t')

d = dict(zip(headers, values))

def f(k):
    val = d.get(k, '-')
    try:
        return f"{float(val):.3f}"
    except:
        return val

out = []

out.append("### Singer Identity Profile: " + d.get("singer", "Unknown"))
out.append("\n#### Table 1: Pitch, Intonation, and Vibrato Dynamics (F0)")
out.append("| Feature Category | Primary Metric | Variance / Dynamics | Range (Min - Max) | Percentiles (p5 - p95) | Distribution (Skew / Kurt) |")
out.append("| :--- | :--- | :--- | :--- | :--- | :--- |")
out.append(f"| **Fundamental Freq (F0)** | {f('f0_mean')} | {f('f0_std')} | {f('f0_min')} to {f('f0_max')} (R: {f('f0_range')}) | {f('f0_p5')} to {f('f0_p95')} (IQR: {f('f0_iqr')}) | Skew: {f('f0_skew')}<br>Kurt: {f('f0_kurt')} |")
out.append(f"| **Pitch Stability** | {f('pitch_stability')} | Mod Var: {f('f0_modulation_variance')} | - | - | Voiced Ratio: {f('voiced_ratio')} |")
out.append(f"| **Vibrato** | Rate: {f('vibrato_rate')} | Depth: {f('vibrato_depth')} | - | - | - |")

out.append("\n#### Table 2: Vocal Tract & Formant Dispersion (F1, F2, F3)")
out.append("| Formant Level | Mean Frequency (Hz) | Std Deviation | Extreme Range (Min - Max) | Percentiles & IQR | Distribution (Skew / Kurt) |")
out.append("| :--- | :--- | :--- | :--- | :--- | :--- |")
for i in [1, 2, 3]:
    out.append(f"| **F{i}** | {f(f'F{i}_mean')} | {f(f'F{i}_std')} | {f(f'F{i}_min')} to {f(f'F{i}_max')} | p5-p95: {f(f'F{i}_p5')} to {f(f'F{i}_p95')}<br>IQR: {f(f'F{i}_iqr')} | Skew: {f(f'F{i}_skew')}<br>Kurt: {f(f'F{i}_kurt')} |")
out.append(f"| **Formant Distances** | F1-F2: {f('F1_F2_distance_mean')} | F2-F3: {f('F2_F3_distance_mean')} | - | - | - |")

out.append("\n#### Table 3: Voice Quality, Spectral Tone & Envelopes")
out.append("| Feature | Mean Value | Variance (Std) | Range (Min - Max) | Percentiles & IQR | Skew / Kurt |")
out.append("| :--- | :--- | :--- | :--- | :--- | :--- |")
out.append(f"| **Perturbation** | Jitter: {f('jitter_mean')} | Shimmer: {f('shimmer_mean')} | - | - | - |")
out.append(f"| **Harmonicity** | HNR: {f('HNR_mean')} | - | - | - | - |")
for feat, name in [('centroid', 'Spectral Centroid'), ('bandwidth', 'Spectral Bandwidth'), ('rolloff', 'Spectral Rolloff'), ('flatness', 'Spectral Flatness')]:
    out.append(f"| **{name}** | {f(feat+'_mean')} | {f(feat+'_std')} | {f(feat+'_min')} to {f(feat+'_max')} | p5-p95: {f(feat+'_p5')} to {f(feat+'_p95')}<br>IQR: {f(feat+'_iqr')} | Skew: {f(feat+'_skew')}<br>Kurt: {f(feat+'_kurt')} |")

out.append("\n#### Table 4: Spectral Contrast Profile (Bands 1 - 7)")
out.append("| Frequency Band | Contrast Mean ± Std | Range (Min - Max) | Extremes (p5 - p95) | IQR | Skew / Kurtosis |")
out.append("| :--- | :--- | :--- | :--- | :--- | :--- |")
for b in range(1, 8):
    out.append(f"| **Band {b}** | {f(f'contrast_band{b}_mean')} ± {f(f'contrast_band{b}_std')} | {f(f'contrast_band{b}_min')} to {f(f'contrast_band{b}_max')} | {f(f'contrast_band{b}_p5')} to {f(f'contrast_band{b}_p95')} | {f(f'contrast_band{b}_iqr')} | Skew: {f(f'contrast_band{b}_skew')}<br>Kurt: {f(f'contrast_band{b}_kurt')} |")

out.append("\n#### Table 5: Mel-Frequency Cepstral Coefficients Matrix (MFCCs 1-13)")
out.append("| MFCC Coeff | Static Mean ± Std | Delta & Delta-Delta | Range (Min - Max) | Percentiles (p5-p95) | IQR | Skew / Kurt |")
out.append("| :--- | :--- | :--- | :--- | :--- | :--- | :--- |")
for m in range(1, 14):
    out.append(f"| **MFCC {m}** | {f(f'mfcc{m}_mean')} ± {f(f'mfcc{m}_std')} | Δ: {f(f'mfcc{m}_delta_mean')}<br>ΔΔ: {f(f'mfcc{m}_delta2_mean')} | {f(f'mfcc{m}_min')} to {f(f'mfcc{m}_max')} | {f(f'mfcc{m}_p5')} to {f(f'mfcc{m}_p95')} | {f(f'mfcc{m}_iqr')} | Skew: {f(f'mfcc{m}_skew')}<br>Kurt: {f(f'mfcc{m}_kurt')} |")

with open('d:/RagaVoiceStudio/tmp_output.md', 'w', encoding='utf-8') as f_out:
    f_out.write('\n'.join(out))
